<div class="page-header d-flex justify-content-between align-items-center"><div><h1>Recurring Billing</h1><p class="text-muted">Generate predictable invoices from maintenance plans and recurring service agreements.</p></div><form method="post" action="/portal/billing/generate"><?=csrf_field()?><button class="btn btn-primary"><i class="fa-solid fa-bolt"></i> Generate due invoices</button></form></div>
<div class="row g-4"><div class="col-lg-5"><div class="card"><div class="card-body"><h2 class="h5">New billing profile</h2><form method="post" action="/portal/billing" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Customer</label><select class="form-select" name="customer_id" required><?php foreach($customers as $c):?><option value="<?=$c['id']?>"><?=e($c['display_name'])?></option><?php endforeach?></select></div><div class="col-12"><label class="form-label">Description</label><input class="form-control" name="description" required></div><div class="col-md-6"><label class="form-label">Amount</label><input type="number" step="0.01" class="form-control" name="amount" required></div><div class="col-md-6"><label class="form-label">Frequency</label><select class="form-select" name="frequency"><option>monthly</option><option>quarterly</option><option>semiannual</option><option>annual</option><option>weekly</option><option>biweekly</option><option>custom</option></select></div><div class="col-md-6"><label class="form-label">Next bill date</label><input type="date" class="form-control" name="next_bill_date" required></div><div class="col-md-6"><label class="form-label">Terms (days)</label><input type="number" class="form-control" name="payment_terms_days" value="15"></div><div class="col-12 form-check ms-2"><input class="form-check-input" type="checkbox" name="auto_email" id="autoEmail" checked><label class="form-check-label" for="autoEmail">Automatically email invoice</label></div><div class="col-12"><button class="btn btn-primary">Save profile</button></div></form></div></div></div><div class="col-lg-7"><div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Customer</th><th>Description</th><th>Amount</th><th>Frequency</th><th>Next bill</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['display_name'])?></td><td><?=e($r['description'])?></td><td><?=money($r['amount'])?></td><td><?=e($r['frequency'])?></td><td><?=e($r['next_bill_date'])?></td></tr><?php endforeach?></tbody></table></div></div></div></div>
